const faultSeverity = $fromAI("faultSeverity", "The fault severity level", "string");
const healthScore = $fromAI("healthScore", "Vehicle health score 0-100", "number");
const faultCodes = $fromAI("faultCodes", "Array of fault codes", "array");

const criticalThreshold = 30;
const highThreshold = 50;

let riskScore = 100 - healthScore;
if (faultSeverity === "CRITICAL") riskScore += 50;
else if (faultSeverity === "HIGH") riskScore += 30;
else if (faultSeverity === "MEDIUM") riskScore += 15;

const exceedsThreshold = riskScore > criticalThreshold;
const requiresImmediateAction = riskScore > highThreshold;

return { riskScore, exceedsThreshold, requiresImmediateAction, threshold: criticalThreshold };
